return await (async function(eda) {
  const fixtureName = '__codex_example___PCB_PrimitiveDimension_modify_' + Date.now();
  const currentProject = await eda.dmt_Project.getCurrentProjectInfo();
  if (!currentProject) { throw new Error('当前没有打开工程，先补齐环境再调试这个案例。'); }
  const currentDocument = await eda.dmt_SelectControl.getCurrentDocumentInfo();
  if (!currentDocument) {
    throw new Error('当前没有活动文档，先打开一个可操作的文档页。');
  }
  if (currentDocument.documentType !== 3) {
    throw new Error('当前文档类型不是 PCB，请先切到 PCB 再运行这个案例。');
  }
  const createdPrimitive = await eda.pcb_PrimitiveDimension.create(
    'Length Dimension',
    [1000, 1000, 1000, 1150, 1600, 1150, 1600, 1000],
    undefined,
    'mil',
    10,
    2,
    false,
  );
  const primitiveId = createdPrimitive?.getState_PrimitiveId?.() ?? createdPrimitive?.primitiveId ?? createdPrimitive?.id;
  if (!primitiveId) { throw new Error('没有创建出可用于修改的测试图元。'); }
  const property = {
    lineWidth: 12,
    precision: 3,
  };
  try {
    const before = await eda.pcb_PrimitiveDimension.get(primitiveId);
    const result = await eda.pcb_PrimitiveDimension.modify(primitiveId, property);
    const after = await eda.pcb_PrimitiveDimension.get(primitiveId);
    return {
      fixtureName,
      primitiveId,
      property,
      before,
      result,
      after,
      cleanupStrategy: 'auto',
    };
  } finally {
    if (primitiveId) { await eda.pcb_PrimitiveDimension.delete([primitiveId]); }
  }
})(eda);
